import{_ as i,o as a,c as e,ae as n}from"./chunks/framework.BGHOrOyn.js";const c=JSON.parse('{"title":"Docker on Kali Linux","description":"Installing Docker on Kali Linux","frontmatter":{"description":"Installing Docker on Kali Linux"},"headers":[],"relativePath":"snippets-and-scripts/install-scripts/docker-on-kali-linux.md","filePath":"snippets-and-scripts/install-scripts/docker-on-kali-linux.md"}'),l={name:"snippets-and-scripts/install-scripts/docker-on-kali-linux.md"};function t(o,s,r,p,k,d){return a(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="docker-on-kali-linux" tabindex="-1">Docker on Kali Linux <a class="header-anchor" href="#docker-on-kali-linux" aria-label="Permalink to &quot;Docker on Kali Linux&quot;">​</a></h1><p>To install Docker on Kali you need to remember that there is already a package named “docker”, therefore Docker has to be installed under a different name. If you install <code>docker</code> you will not end up with the container version. The version we will be installing is named <code>docker.io</code>. All commands are the same however, so running <code>docker</code> on the command line will be the appropriate command:</p><div class="language-console vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">console</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kali@kali:~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ sudo apt update</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kali@kali:~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kali@kali:~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ sudo apt install -y docker.io</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kali@kali:~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kali@kali:~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ sudo systemctl enable docker --now</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kali@kali:~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kali@kali:~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ docker</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kali@kali:~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$</span></span></code></pre></div><p>You can now get started with using docker, with <code>sudo</code>. If you want to add yourself to the docker group to use <code>docker</code> without <code>sudo</code>, an additional step is needed:</p><div class="language-console vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">console</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kali@kali:~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ sudo usermod -aG docker $USER</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kali@kali:~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$</span></span></code></pre></div><p>The final thing is to <strong>logout and in again</strong>.</p><p>If you would like to use a Kali Docker image, we have a doc page for that <a href="https://www.kali.org/docs/containers/using-kali-docker-images/" target="_blank" rel="noreferrer">here</a>.</p><p><a href="https://www.kali.org/docs/containers/installing-docker-on-kali/#installing-docker-ce-on-kali-linux" target="_blank" rel="noreferrer"><strong>Installing docker-ce on Kali Linux</strong></a></p><p><code>docker-ce</code> can be installed from Docker repository. One thing to bear in mind, <a href="https://www.kali.org/docs/policy/kali-linux-relationship-with-debian/" target="_blank" rel="noreferrer">Kali Linux is based on Debian</a>, so we need to use <a href="https://www.debian.org/releases/stable/" target="_blank" rel="noreferrer">Debian’s current stable version</a> (even though Kali Linux is a <a href="https://www.kali.org/docs/general-use/kali-branches/" target="_blank" rel="noreferrer">rolling distribution</a>). At the time of writing (Dec. 2021), its “bullseye”:</p><div class="language-console vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">console</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kali@kali:~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ printf </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;%s\\n&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;deb https://download.docker.com/linux/debian bullseye stable&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  sudo tee /etc/apt/sources.list.d/docker-ce.list</span></span></code></pre></div><p>Import the gpg key:</p><div class="language-console vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">console</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kali@kali:~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ curl -fsSL https://download.docker.com/linux/debian/gpg </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  sudo gpg --dearmor -o /etc/apt/trusted.gpg.d/docker-ce-archive-keyring.gpg</span></span></code></pre></div><p>Install the latest version of <code>docker-ce</code>:</p><div class="language-console vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">console</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kali@kali:~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ sudo apt update</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kali@kali:~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ sudo apt install -y docker-ce docker-ce-cli containerd.io</span></span></code></pre></div><p><a href="https://www.kali.org/docs/containers/installing-docker-on-kali/#references" target="_blank" rel="noreferrer"><br></a></p>`,15)])])}const g=i(l,[["render",t]]);export{c as __pageData,g as default};
